/* Reliable documentation PDF path: open a printable document view instead of raw PDF bytes */
function buildTechnicalDocumentationPrintHtml() {
  const rows = technicalDocSections().map(([type, text]) => {
    if (type === "title") return '<h1 class="doc-title">' + escapeHtml(text) + '</h1>';
    if (type === "h1") return '<h2>' + escapeHtml(text) + '</h2>';
    return '<p>' + escapeHtml(text) + '</p>';
  }).join("");

  return '<!doctype html><html><head><meta charset="utf-8"><title>Pallet Check Tool - Technical Documentation</title>' +
    '<style>' +
    '@page{size:A4;margin:18mm 18mm 16mm 18mm;}' +
    'body{font-family:Arial,Helvetica,sans-serif;color:#162435;background:#fff;line-height:1.45;font-size:10.5pt;}' +
    '.page{max-width:780px;margin:0 auto;}' +
    '.eyebrow{font-size:8.5pt;letter-spacing:.08em;text-transform:uppercase;color:#5d7084;margin-bottom:8px;}' +
    '.doc-title{font-size:24pt;line-height:1.12;margin:0 0 8px;color:#0b3157;}' +
    '.subtitle{font-size:10pt;color:#5d7084;border-bottom:1px solid #d8e1ea;padding-bottom:16px;margin-bottom:18px;}' +
    'h2{font-size:13.5pt;line-height:1.25;color:#0b5cab;margin:18px 0 6px;page-break-after:avoid;}' +
    'p{margin:0 0 8px;}' +
    '.footer{margin-top:22px;padding-top:10px;border-top:1px solid #d8e1ea;color:#6b7c8e;font-size:8.5pt;}' +
    '@media print{.no-print{display:none!important;}body{font-size:10pt;}h2{break-after:avoid;}}' +
    '</style></head><body><div class="page"><div class="eyebrow">Standalone HTML maintenance guide</div>' +
    rows +
    '<div class="footer">Generated from Pallet_Check_Tool.html. This documentation is embedded in the standalone tool file.</div>' +
    '<script>setTimeout(function(){window.focus();window.print();},250);<\/script>' +
    '</div></body></html>';
}

function downloadTechnicalPdf(event) {
  if (event) event.preventDefault();
  const printWindow = window.open("", "_blank");
  if (!printWindow) {
    alert("Please allow pop-ups for this page to open the PDF print view.");
    return;
  }
  printWindow.document.open();
  printWindow.document.write(buildTechnicalDocumentationPrintHtml());
  printWindow.document.close();
}

function configureTechnicalPdfDownload() {
  const link = document.querySelector(".doc-download-card .doc-download-link");
  if (!link) return;
  link.setAttribute("href", "#");
  link.removeAttribute("download");
  link.textContent = "Download PDF";
  link.onclick = downloadTechnicalPdf;
}
